pub fn initialize_database(db: &Database) -> Result<()> {
    let existing = db.get_ingredients(None, None)?;
    if !existing.is_empty() {
        return Ok(());
    }

    let ingredients = get_initial_ingredients();
    for ing in ingredients {
        let _ = db.create_ingredient(ing);
    }

    Ok(())
}